// Core math and random utilities for p5.oil
const { abs, sin, cos, sqrt, PI, floor, min, max, pow, atan2, random: mathRandom, log, exp } = Math;
const TAU = PI * 2;

// Seeded PRNG (Mulberry32)
let _seed = 42;
export function seed(s) { _seed = s | 0; }
export function rand01() {
  _seed |= 0; _seed = _seed + 0x6D2B79F5 | 0;
  let t = Math.imul(_seed ^ _seed >>> 15, 1 | _seed);
  t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
  return ((t ^ t >>> 14) >>> 0) / 4294967296;
}
export function rand(a, b) { return a + rand01() * (b - a); }
export function randInt(a, b) { return floor(rand(a, b + 0.99)); }
export function pick(arr) { return arr[randInt(0, arr.length - 1)]; }
export function gauss() {
  let u = 0, v = 0;
  while (!u) u = rand01();
  while (!v) v = rand01();
  return sqrt(-2 * log(u)) * cos(TAU * v);
}

export function lerp(a, b, t) { return a + (b - a) * t; }
export function clamp(v, lo, hi) { return max(lo, min(hi, v)); }

// 1D Noise
export class Noise {
  constructor(s = 42) {
    this.p = new Uint8Array(512);
    for (let i = 0; i < 256; i++) {
      s = (s * 16807) % 2147483647;
      this.p[i] = this.p[i + 256] = s & 255;
    }
  }
  _fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  _grad(h, x) { return (h & 1) ? -x : x; }
  n(x) {
    const i = floor(x) & 255, f = x - floor(x), u = this._fade(f);
    return lerp(this._grad(this.p[i], f), this._grad(this.p[i + 1], f - 1), u);
  }
  fbm(x, oct = 4) {
    let v = 0, a = 1, fr = 1, mx = 0;
    for (let i = 0; i < oct; i++) { v += this.n(x * fr) * a; mx += a; a *= 0.5; fr *= 2; }
    return v / mx;
  }
}

// Color utilities
export function hsl2rgb(h, s, l) {
  h = ((h % 360) + 360) % 360; s = clamp(s, 0, 1); l = clamp(l, 0, 1);
  const c = (1 - abs(2 * l - 1)) * s, x = c * (1 - abs((h / 60) % 2 - 1)), m = l - c / 2;
  let r, g, b;
  if (h < 60) { r = c; g = x; b = 0; }
  else if (h < 120) { r = x; g = c; b = 0; }
  else if (h < 180) { r = 0; g = c; b = x; }
  else if (h < 240) { r = 0; g = x; b = c; }
  else if (h < 300) { r = x; g = 0; b = c; }
  else { r = c; g = 0; b = x; }
  return [(r + m), (g + m), (b + m)];
}

export function parseColor(c) {
  // Returns [r, g, b] in 0-1 range
  if (Array.isArray(c)) {
    if (c.length >= 3) return [c[0] / 255, c[1] / 255, c[2] / 255];
    return [c[0] / 255, c[0] / 255, c[0] / 255]; // grayscale
  }
  if (typeof c === "string") {
    if (c.startsWith("#")) {
      const hex = c.slice(1);
      const n = parseInt(hex, 16);
      if (hex.length === 3) return [((n >> 8) & 0xf) / 15, ((n >> 4) & 0xf) / 15, (n & 0xf) / 15];
      return [((n >> 16) & 0xff) / 255, ((n >> 8) & 0xff) / 255, (n & 0xff) / 255];
    }
  }
  if (typeof c === "number") return [c / 255, c / 255, c / 255];
  // p5.Color object
  if (c && typeof c.levels !== "undefined") {
    const l = c.levels || c._array;
    if (l) return [l[0] / 255, l[1] / 255, l[2] / 255];
  }
  return [0, 0, 0];
}

export { abs, sin, cos, sqrt, PI, TAU, floor, min, max, pow, atan2, log, exp };
