// p5.js addon registration for p5.oil
// Follows the same pattern as p5.brush: registerAddon(registerP5Addon)
import { GLEngine } from "../../stroke/gl_engine.js";
import * as strokeAPI from "../../stroke/stroke.js";
import { parseColor, seed as setSeed } from "../../core/utils.js";

let _engine = null;
let _p5Instance = null;
let _bound = false;

function getGL(inst) {
  // Access the underlying WebGL2 context from p5's WEBGL renderer
  const r = inst._renderer;
  if (r && r.GL) return r.GL;
  if (r && r.drawingContext && r.drawingContext instanceof WebGL2RenderingContext) return r.drawingContext;
  if (inst.drawingContext && inst.drawingContext instanceof WebGL2RenderingContext) return inst.drawingContext;
  return null;
}

export function registerP5Addon(_p5, fn, lifecycles) {
  _engine = new GLEngine();

  // --- Lifecycle hooks ---
  lifecycles.postsetup = function () {
    _p5Instance = this;
    const gl = getGL(this);
    if (gl && !_bound) {
      _engine.init(gl);
      _bound = true;
    }
  };

  lifecycles.predraw = function () {
    _p5Instance = this;
    if (!_bound) {
      const gl = getGL(this);
      if (gl) { _engine.init(gl); _bound = true; }
    }
  };

  lifecycles.postdraw = function () {
    if (_engine.ready) _engine.flush();
  };

  // --- Wrap push/pop ---
  const _origPush = fn.push;
  const _origPop = fn.pop;
  fn.push = function () { _origPush && _origPush.call(this); strokeAPI.pushState(); };
  fn.pop = function () { _origPop && _origPop.call(this); strokeAPI.popState(); };

  // --- Public API on fn namespace (oil.*) ---

  fn.set = function (brush, color, weight) {
    if (color !== undefined) {
      const c = parseColor(color);
      strokeAPI.setColor(c);
    }
    strokeAPI.set(brush, undefined, weight);
  };

  fn.pick = function (brush) { strokeAPI.pick(brush); };

  fn.stroke = function (r, g, b) {
    if (g === undefined) {
      const c = parseColor(r);
      strokeAPI.strokeColor(c[0], c[1], c[2]);
    } else {
      strokeAPI.strokeColor(r, g, b);
    }
    strokeAPI.enableStroke();
  };

  fn.noStroke = function () { strokeAPI.noStroke(); };
  fn.strokeWeight = function (w) { strokeAPI.strokeWeight(w); };

  fn.box = function () { return strokeAPI.box(); };

  fn.add = function (name, params) { strokeAPI.add(name, params); };

  fn.seed = function (s) { setSeed(s); };

  // --- Drawing primitives ---

  fn.line = function (x1, y1, x2, y2) {
    strokeAPI.drawStroke(_engine, x1, y1, x2, y2);
  };

  fn.flowLine = function (x, y, length, direction) {
    strokeAPI.drawFlowStroke(_engine, x, y, length, direction);
  };

  fn.rect = function (x, y, w, h) {
    // Draw rect as 4 lines
    strokeAPI.drawStroke(_engine, x, y, x + w, y);
    strokeAPI.drawStroke(_engine, x + w, y, x + w, y + h);
    strokeAPI.drawStroke(_engine, x + w, y + h, x, y + h);
    strokeAPI.drawStroke(_engine, x, y + h, x, y);
  };

  fn.circle = function (x, y, r) {
    // Draw circle as polygon segments
    const segs = Math.max(12, Math.floor(r * 0.5));
    for (let i = 0; i < segs; i++) {
      const a0 = (i / segs) * Math.PI * 2;
      const a1 = ((i + 1) / segs) * Math.PI * 2;
      strokeAPI.drawStroke(_engine,
        x + Math.cos(a0) * r, y + Math.sin(a0) * r,
        x + Math.cos(a1) * r, y + Math.sin(a1) * r
      );
    }
  };

  fn.spline = function (points, curvature) {
    strokeAPI.drawSpline(_engine, points, curvature);
  };

  // Flush on demand
  fn.flush = function () {
    if (_engine.ready) _engine.flush();
  };

  fn.scaleBrushes = function (s) {
    // Scale is applied via strokeWeight
  };
}
