// Unique pressure curve generators for oil brushes
import { rand, rand01, gauss, clamp, pow, sin, PI, max } from "./utils.js";

// Generate a unique pressure profile for each stroke
export function makePressureCurve() {
  const type = (rand01() * 6) | 0;
  const peak = rand(0.2, 0.8);
  const asymm = rand(0.5, 2);
  const jitter = rand(0, 0.1);
  const plateauW = rand(0.15, 0.5);

  return function pressureFn(t) {
    let p;
    switch (type) {
      case 0: // Bell curve (asymmetric)
        p = Math.exp(-pow((t - peak) / (t < peak ? 0.3 * asymm : 0.3 / asymm), 2));
        break;
      case 1: // Ramp up then sudden drop
        p = t < peak ? pow(t / peak, rand(0.5, 2)) : pow(max(0, 1 - (t - peak) / (1 - peak)), rand(2, 5));
        break;
      case 2: // Plateau with soft edges
        p = t < peak - plateauW / 2 ? pow(t / (peak - plateauW / 2), rand(0.5, 1.5))
          : t > peak + plateauW / 2 ? pow(max(0, 1 - (t - peak - plateauW / 2) / (1 - peak - plateauW / 2)), rand(0.5, 1.5))
          : 1;
        break;
      case 3: // Double hump
        p = max(0, sin(t * PI) * 0.5 + sin(t * PI * 2.3 + rand(0, PI)) * 0.5);
        break;
      case 4: // Attack-sustain-release
        p = t < 0.15 ? t / 0.15 : t > 0.8 ? (1 - t) / 0.2 : rand(0.7, 1);
        break;
      default: // Exponential fade
        p = pow(max(0, 1 - t), rand(0.3, 1.5));
        break;
    }
    return clamp(p + gauss() * jitter, 0.05, 1);
  };
}

// Preset pressure curves that can be passed by name
export const pressurePresets = {
  uniform: () => (t) => 1,
  bell: () => (t) => Math.exp(-pow((t - 0.5) / 0.3, 2)),
  fadeOut: () => (t) => pow(max(0, 1 - t), 0.8),
  fadeIn: () => (t) => pow(t, 0.8),
  random: makePressureCurve,
};
