// Oil brush stroke renderer
// Generates bristle-based strokes and emits circle primitives to the GL engine.
import { rand, randInt, gauss, clamp, lerp, Noise, abs, sin, cos, pow, PI, max, floor } from "../core/utils.js";
import { makePressureCurve } from "../core/pressure.js";
import { builtinBrushes } from "./brushes.js";

// ============================================================
// STATE
// ============================================================
let _currentBrush = "filbertMedium";
let _color = [0.3, 0.2, 0.1]; // r, g, b in 0-1
let _weight = 10; // stroke width in px
let _opacity = 1.0;
let _hasStroke = true;
const _customBrushes = {};

// State stack for push/pop
const _stack = [];

export function pushState() {
  _stack.push({ brush: _currentBrush, color: [..._color], weight: _weight, opacity: _opacity, hasStroke: _hasStroke });
}
export function popState() {
  if (_stack.length === 0) return;
  const s = _stack.pop();
  _currentBrush = s.brush; _color = s.color; _weight = s.weight; _opacity = s.opacity; _hasStroke = s.hasStroke;
}

// ============================================================
// PUBLIC API
// ============================================================

export function set(brushName, color, weight) {
  if (brushName) _currentBrush = brushName;
  if (color !== undefined) setColor(color);
  if (weight !== undefined) _weight = weight;
}

export function setColor(c) {
  if (Array.isArray(c)) {
    _color = c[0] > 1 ? [c[0] / 255, c[1] / 255, c[2] / 255] : [...c];
  } else if (typeof c === "number") {
    const v = c > 1 ? c / 255 : c;
    _color = [v, v, v];
  }
}

export function strokeColor(r, g, b) {
  if (g === undefined) { setColor(r); return; }
  _color = [r > 1 ? r / 255 : r, g > 1 ? g / 255 : g, b > 1 ? b / 255 : b];
}

export function strokeWeight(w) { _weight = w; }
export function noStroke() { _hasStroke = false; }
export function enableStroke() { _hasStroke = true; }
export function pick(name) { _currentBrush = name; }

export function box() {
  return [...Object.keys(builtinBrushes), ...Object.keys(_customBrushes)];
}

export function add(name, params) {
  _customBrushes[name] = { ...params };
}

// ============================================================
// BRUSH DEFINITION LOOKUP
// ============================================================
function getBrushDef() {
  return _customBrushes[_currentBrush] || builtinBrushes[_currentBrush] || builtinBrushes.filbertMedium;
}

function randRange(arr) {
  if (!Array.isArray(arr)) return arr;
  return rand(arr[0], arr[1]);
}

// ============================================================
// STROKE RENDERING — generates circle primitives for the GL engine
// ============================================================

export function drawStroke(glEngine, x0, y0, x1, y1) {
  if (!_hasStroke) return;
  const def = getBrushDef();
  const dx = x1 - x0, dy = y1 - y0;
  const len = Math.sqrt(dx * dx + dy * dy);
  if (len < 1) return;
  const angle = Math.atan2(dy, dx);

  _drawBristleStroke(glEngine, x0, y0, len, angle, def);
}

export function drawFlowStroke(glEngine, x0, y0, length, direction) {
  if (!_hasStroke) return;
  const def = getBrushDef();
  _drawBristleStroke(glEngine, x0, y0, length, direction, def);
}

export function drawSpline(glEngine, points, curvature) {
  if (!_hasStroke || points.length < 2) return;
  const def = getBrushDef();
  // Draw segments between points
  for (let i = 0; i < points.length - 1; i++) {
    const p0 = points[i], p1 = points[i + 1];
    const dx = p1.x - p0.x, dy = p1.y - p0.y;
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len < 1) continue;
    const angle = Math.atan2(dy, dx);
    _drawBristleStroke(glEngine, p0.x, p0.y, len, angle, def);
  }
}

// ============================================================
// CORE BRISTLE STROKE ENGINE
// ============================================================

function _drawBristleStroke(engine, x0, y0, len, baseAngle, def) {
  const noise = new Noise(randInt(0, 99999));
  const width = _weight * def.weight;
  const bristles = randInt(randRange(def.bristles) * 0.8, randRange(def.bristles) * 1.2);
  const taper = randRange(def.taper);
  const oval = randRange(def.oval);
  const curveSway = randRange(def.curveSway);
  const curveFreq = rand(0.5, 3);
  const deplete = randRange(def.deplete);
  const chaos = randRange(def.chaos);
  const baseAlpha = randRange(def.opacity) * _opacity;
  const twist = rand(-0.4, 0.4);
  const dryBrush = Math.random() < def.dryBrush ? rand(0.3, 1) : 0;
  const pressureFn = makePressureCurve();

  const steps = max(8, floor(len / 1));
  const spacing = def.spacing || 1;

  // Build path with curvature
  const path = new Float64Array((steps + 1) * 3); // x, y, angle
  let px = x0, py = y0, curA = baseAngle;
  path[0] = px; path[1] = py; path[2] = curA;
  for (let i = 1; i <= steps; i++) {
    const t = i / steps;
    curA = baseAngle
      + curveSway * sin(t * PI * curveFreq)
      + curveSway * 0.3 * sin(t * PI * curveFreq * 2.7 + rand(0, PI))
      + noise.fbm(t * 4, 3) * 0.15 * chaos;
    px += cos(curA) * (len / steps);
    py += sin(curA) * (len / steps);
    const idx = i * 3;
    path[idx] = px; path[idx + 1] = py; path[idx + 2] = curA;
  }

  // Layers — thicker brushes get 2 layers
  const layers = width > 15 && Math.random() > 0.4 ? 2 : 1;

  for (let layer = 0; layer < layers; layer++) {
    // Per-layer color shift
    const lr = clamp(_color[0] + rand(-0.04, 0.04) * chaos, 0, 1);
    const lg = clamp(_color[1] + rand(-0.03, 0.03) * chaos, 0, 1);
    const lb = clamp(_color[2] + rand(-0.03, 0.03) * chaos, 0, 1);

    for (let b = 0; b < bristles; b++) {
      const bN = b / max(1, bristles - 1);
      const bOff = (bN - 0.5) * width;
      const edgeDist = abs(bN - 0.5) * 2;

      // Each bristle has unique personality
      const bStiff = rand(0.5, 1.5);
      const bWand = rand(0.3, 2.5) * chaos;
      const bThick = rand(0.6, 1.8);
      const bGrain = rand(0, 0.4);
      const ovalF = oval < 1 ? pow(max(0, 1 - pow(edgeDist, 2)), oval) : 1;

      // Per-bristle color micro-shift
      const br = clamp(lr + rand(-0.02, 0.02), 0, 1);
      const bg = clamp(lg + rand(-0.015, 0.015), 0, 1);
      const bb = clamp(lb + rand(-0.015, 0.015), 0, 1);

      const edgeFade = 1 - pow(edgeDist, rand(1, 2.5));
      const bristleAlpha = clamp(baseAlpha * (0.1 + edgeFade * 0.7) * (0.7 + layer * 0.2) * rand(0.6, 1.3), 0.01, 0.85);

      // Walk along path emitting circles
      const stepSkip = max(1, floor(spacing * 1.5));
      for (let i = 0; i <= steps; i += stepSkip) {
        const t = i / steps;
        const idx = min(i, steps) * 3;
        const ptX = path[idx], ptY = path[idx + 1], ptA = path[idx + 2];

        const pressure = pressureFn(t);
        const taperF = pow(sin(clamp(t * PI, 0, PI)), taper);
        const deplF = 1 - t * deplete;
        const twistF = 1 + twist * sin(t * PI * rand(1, 3));

        // Dry brush gap
        if (dryBrush > 0 && Math.random() < bGrain * dryBrush && t > 0.3) continue;

        const totalOff = bOff * taperF * ovalF * pressure * twistF * deplF;
        const wander = noise.fbm(t * 6 * bStiff + b * 0.7 + layer * 3, 3) * bWand * 3;
        const ox = (-sin(ptA)) * (totalOff + wander);
        const oy = (cos(ptA)) * (totalOff + wander);

        const radius = max(0.3, width / bristles * bThick * ovalF * pressure * 0.5);

        engine.addCircle(
          ptX + ox, ptY + oy,
          radius,
          br, bg, bb,
          bristleAlpha * pressure * deplF
        );
      }
    }
  }

  // Specular highlight — occasional bright ridge
  if (Math.random() > 0.5) {
    const hlStart = floor(steps * rand(0.15, 0.4));
    const hlEnd = floor(steps * rand(0.5, 0.85));
    for (let i = hlStart; i <= hlEnd; i += max(1, floor(spacing * 3))) {
      const idx = min(i, steps) * 3;
      const ptX = path[idx], ptY = path[idx + 1], ptA = path[idx + 2];
      const off = rand(-width * 0.3, width * 0.3);
      engine.addCircle(
        ptX + (-sin(ptA)) * off,
        ptY + (cos(ptA)) * off,
        rand(0.3, 1.5),
        1, 1, 0.95,
        rand(0.01, 0.05)
      );
    }
  }
}
